module RefModule(
    input [3:0] dividend,
    input [3:0] divisor,
    output reg [3:0] quotient
);
    reg [4:0] obf_remainder;
    integer i;

    always @(*) begin
        obf_remainder = 0;
        quotient = 0;

        for (i = 3; i >= 0; i = i - 1) begin
            obf_remainder = {obf_remainder[3:0], dividend[i]};
            if (obf_remainder >= divisor) begin
                obf_remainder = obf_remainder - divisor;
                quotient[i] = 1;
            end else begin
                quotient[i] = 0;
            end
        end
    end
endmodule
